// Parse and normalize all Retell post-call data fields
const items = $input.all();
const raw = items[0].json.body || items[0].json;

// Extract call metadata from Retell payload
const callId = raw.call_id || raw.callId || 'unknown';
const agentId = raw.agent_id || raw.agentId || '';
const fromNumber = raw.from_number || raw.fromNumber || '';
const toNumber = raw.to_number || raw.toNumber || '';
const callDuration = raw.call_duration_ms || raw.duration || 0;
const callTimestamp = raw.start_timestamp || raw.created_at || new Date().toISOString();
const disconnectReason = raw.disconnect_reason || raw.disconnection_reason || '';

// Extract post-call data retrieval variables
const pcdr = raw.call_analysis || raw.custom_analysis_data || raw;

const callSummary = pcdr.Call_Summary || pcdr.call_summary || pcdr.Call_summary || '';
const callSuccessful = pcdr.Call_Successful === true || pcdr.Call_Successful === 'true' || pcdr.call_successful === true || false;
const userSentiment = pcdr.User_Sentiment || pcdr.user_sentiment || '';
const callerEmail = pcdr.Callers_email_id || pcdr.callers_email_id || pcdr['Caller\'s email id'] || pcdr.caller_email || '';
const advisorTransferCompleted = pcdr.advisor_transfer_completed === true || pcdr.advisor_transfer_completed === 'true' || false;
const callbackDate = pcdr.callback_date || '';
const coverageTypeRequested = pcdr.coverage_type_requested || '';
const callBackScheduled = pcdr.call_back_scheduled === true || pcdr.call_back_scheduled === 'true' || false;
const callBackReason = pcdr.call_back_reason || '';
const customerSentiment = pcdr.Customer_sentiment || pcdr.customer_sentiment || '';
const userConsentForRecording = pcdr.User_consent_for_recording === true || pcdr.User_consent_for_recording === 'true' || pcdr.user_consent_for_recording === true || false;
const callerName = pcdr.Caller_Name || pcdr.caller_name || pcdr.CallerName || 'Unknown';
const leadDisposition = pcdr.lead_disposition || pcdr.Lead_disposition || 'unknown';
const voicemail = pcdr.Voicemail === true || pcdr.Voicemail === 'true' || pcdr.voicemail === true || false;
const callbackScheduledTime = pcdr.callback_scheduled_time || '';

// Normalize lead disposition to standard values
const dispositionMap = {
  'interested': 'interested',
  'hot_lead': 'interested',
  'callback_scheduled': 'callback_scheduled',
  'callback': 'callback_scheduled',
  'appointment_booked': 'appointment_booked',
  'appointment': 'appointment_booked',
  'booked': 'appointment_booked',
  'not_interested': 'not_interested',
  'declined': 'not_interested',
  'opt_out': 'not_interested',
  'voicemail': 'voicemail',
  'no_answer': 'voicemail',
  'transfer_completed': 'transfer_completed',
  'transferred': 'transfer_completed',
  'unknown': 'unknown'
};

const normalizedDisposition = dispositionMap[leadDisposition.toLowerCase().replace(/[\s-]/g, '_')] || leadDisposition.toLowerCase();

return [{
  json: {
    // Call metadata
    call_id: callId,
    agent_id: agentId,
    from_number: fromNumber,
    to_number: toNumber,
    call_duration_ms: callDuration,
    call_timestamp: callTimestamp,
    disconnect_reason: disconnectReason,
    processed_at: new Date().toISOString(),

    // Post-call data retrieval fields
    call_summary: callSummary,
    call_successful: callSuccessful,
    user_sentiment: userSentiment,
    caller_email: callerEmail,
    advisor_transfer_completed: advisorTransferCompleted,
    callback_date: callbackDate,
    coverage_type_requested: coverageTypeRequested,
    call_back_scheduled: callBackScheduled,
    call_back_reason: callBackReason,
    customer_sentiment: customerSentiment,
    user_consent_for_recording: userConsentForRecording,
    caller_name: callerName,
    lead_disposition: leadDisposition,
    normalized_disposition: normalizedDisposition,
    voicemail: voicemail,
    callback_scheduled_time: callbackScheduledTime
  }
}];

// Prepare Google Calendar event for appointment
const item = $input.all()[0].json;

const callerName = item.caller_name || 'Prospect';
const coverageType = item.coverage_type_requested || 'Insurance Consultation';
const callbackDate = item.callback_date || '';
const callbackTime = item.callback_scheduled_time || '';
const callerEmail = item.caller_email || '';
const phone = item.from_number || '';
const summary = item.call_summary || '';

// Parse appointment date/time
let startDateTime, endDateTime;
if (callbackDate && callbackTime) {
  const dateStr = `${callbackDate}T${callbackTime}`;
  startDateTime = new Date(dateStr).toISOString();
  endDateTime = new Date(new Date(dateStr).getTime() + 30 * 60000).toISOString(); // 30 min
} else if (callbackDate) {
  startDateTime = new Date(`${callbackDate}T10:00:00`).toISOString();
  endDateTime = new Date(`${callbackDate}T10:30:00`).toISOString();
} else {
  // Default to tomorrow 10 AM
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  tomorrow.setHours(10, 0, 0, 0);
  startDateTime = tomorrow.toISOString();
  endDateTime = new Date(tomorrow.getTime() + 30 * 60000).toISOString();
}

return [{
  json: {
    ...item,
    event_summary: `${coverageType} — ${callerName}`,
    event_description: `Coverage Type: ${coverageType}\nCaller: ${callerName}\nPhone: ${phone}\nEmail: ${callerEmail}\n\nCall Summary:\n${summary}`,
    event_start: startDateTime,
    event_end: endDateTime,
    attendee_email: callerEmail
  }
}];

// Log opt-out / not interested — no email or SMS (TCPA compliance)
const item = $input.all()[0].json;
return [{
  json: {
    ...item,
    action: 'opt_out_logged',
    note: 'Lead marked not interested. No further contact per TCPA compliance.'
  }
}];

// Handle unknown/fallback dispositions
const item = $input.all()[0].json;
return [{
  json: {
    ...item,
    action: 'fallback_logged',
    note: `Unknown disposition: ${item.lead_disposition}. Logged for manual review.`
  }
}];
